5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  items: Item[];
14	}
15	
16	export interface QuoteResult {
17	  premium: number;
18	}
19	
20	// Runes and moonstones are "components" — a distinct pricing tier that shares
21	// one base premium (and, later, block/alike rules). Naming the shared value
22	// makes the equality intentional rather than a coincidence two entries happen
23	// to share.
24	const COMPONENT_BASE_PREMIUM = 25;
25	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
26	// A "building block" of exactly this many alike components is offered at a
27	// special block premium instead of the per-component price.
28	const COMPONENT_BLOCK_SIZE = 3;
29	const COMPONENT_BLOCK_PREMIUM = 60;
30	
31	const BASE_PREMIUMS: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: COMPONENT_BASE_PREMIUM,
37	  moonstone: COMPONENT_BASE_PREMIUM,
38	};
39	const PROCESSING_FEE = 5;
40	
41	// Surcharges are expressed as integer percentages and applied as
42	// `amount * percent / 100`, keeping the maths in integers (avoids float errors
43	// such as `100 * 1.1 === 100.00000000000001`).
44	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
45	const CURSE_SURCHARGE_PERCENT = 50;
46	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
47	const HIGH_ENCHANTMENT_MIN_LEVEL = 5;
48	const LOYALTY_DISCOUNT_PERCENT = 20;
49	const LOYALTY_MIN_YEARS = 2;
50	
51	const percentOf = (amount: number, percent: number): number =>
52	  (amount * percent) / 100;
53	
54	// A single item's base premium. BASE_PREMIUMS is the single source of truth
55	// for per-type base prices (components included), so a plain lookup suffices —
56	// block pricing is a group-level concern handled separately in sumBasePremiums.
57	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
58	
59	// Item-specific surcharges, each a percentage of the item's own base premium:
60	// a curse adds 50%, and a highly-enchanted item (level >= 5) adds 30%. They
61	// stack when both apply.
62	const itemSurcharge = (item: Item): number => {
63	  const base = itemBasePremium(item);
64	  const curse = item.cursed ? percentOf(base, CURSE_SURCHARGE_PERCENT) : 0;
65	  const highEnchantment =
66	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_MIN_LEVEL
67	      ? percentOf(base, HIGH_ENCHANTMENT_SURCHARGE_PERCENT)
68	      : 0;
69	  return curse + highEnchantment;
70	};
71	
72	const sumItemSurcharges = (items: Item[]): number =>
73	  items.reduce((total, item) => total + itemSurcharge(item), 0);
74	
75	const countByType = (items: Item[]): Map<string, number> => {
76	  const counts = new Map<string, number>();
77	  for (const item of items) {
78	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
79	  }
80	  return counts;
81	};
82	
83	const componentGroupPremium = (count: number): number =>
84	  count === COMPONENT_BLOCK_SIZE
85	    ? COMPONENT_BLOCK_PREMIUM
86	    : count * COMPONENT_BASE_PREMIUM;
87	
88	const typeGroupPremium = (type: string, count: number): number =>
89	  COMPONENT_TYPES.has(type)
90	    ? componentGroupPremium(count)
91	    : count * (BASE_PREMIUMS[type] ?? 0);
92	
93	const sumBasePremiums = (items: Item[]): number =>
94	  [...countByType(items)].reduce(
95	    (total, [type, count]) => total + typeGroupPremium(type, count),
96	    0,
97	  );
98	
99	// Policy-wide modifiers scale with the whole policy's base premium.
100	// First-insurance is a surcharge every new policy pays; the loyalty discount
101	// rewards customers at or past the loyalty threshold.
102	const firstInsuranceSurcharge = (policyBase: number): number =>
103	  percentOf(policyBase, FIRST_INSURANCE_SURCHARGE_PERCENT);
104	
105	const loyaltyDiscount = (customer: Customer, policyBase: number): number =>
106	  customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS
107	    ? percentOf(policyBase, LOYALTY_DISCOUNT_PERCENT)
108	    : 0;
109	
110	export const quote = (
111	  customer: Customer,
112	  step: QuoteStep,
113	  _quoteIndex: number,
114	): QuoteResult => {
115	  const policyBase = sumBasePremiums(step.items);
116	  const premium = Math.ceil(
117	    policyBase +
118	      sumItemSurcharges(step.items) +
119	      firstInsuranceSurcharge(policyBase) -
120	      loyaltyDiscount(customer, policyBase) +
121	      PROCESSING_FEE,
122	  );
123	  return { premium };
124	};
125	
126	export const claim = (): unknown => {
127	  return undefined;
128	};
